-- ==========================================================
-- accounts seed — Түмэн Тээх ХХК-ийн дансны төлөвлөгөө
-- Эх сурвалж: Дансны_Төлөвлөгөө_TT.xlsx (151 навч + класс/бүлгийн эх данс)
-- Код: AABBCC. Хоёр хэл (name/name_en), зардалд МУСГАА/татвар note.
-- Хүснэгт хоосон үед л оруулна. Supabase SQL Editor-д ажиллуулна.
-- Нийт: 218 данс (151 навч + 19 класс + 48 бүлэг).
-- ==========================================================

DO $$
BEGIN
IF (SELECT COUNT(*) FROM accounts) = 0 THEN


PERFORM setval(pg_get_serial_sequence('accounts','id'),
               (SELECT MAX(id) FROM accounts));

END IF;
END $$;
